const IMAGING_TYPES = new Set<string>([
  "Centre de diagnostic",
  "Centre de excelență oncologică",
]);

export const imagingClinics: AffideaClinic[] = affideaClinics.filter((c) => IMAGING_TYPES.has(c.type));

// Suburbs that share a parent city's map pin and popover.
const CITY_ALIAS: Record<string, string> = { "Sat Scheia, Comuna Scheia": "Suceava" };
const cityKey = (c: string) => CITY_ALIAS[c] ?? c;

export function imagingClinicsInCity(cityTitle: string): AffideaClinic[] {
  return imagingClinics.filter((c) => cityKey(c.city) === cityTitle);
}

